class Solution:
    def minimumCost(self, source, target, original, changed, cost):
        m = len(cost)
        f = [[float("inf")]*26 for _ in range(26)]
        for i in range(26):
            f[i][i] = 0
        for j in range(m):
            a = ord(original[j])-97
            b = ord(changed[j])-97
            w = cost[j]
            f[a][b] = min(f[a][b], w)

        for k in range(26):
            for i in range(26):
                if f[i][k] == float("inf"):
                    continue
                for j in range(26):
                    f[i][j] = min(f[i][j], f[i][k]+f[k][j])
    
        ans = 0
        for k in range(len(source)):
            if source[k] != target[k]:
                x = ord(source[k])-97
                y = ord(target[k])-97
                if f[x][y] == float("inf"):
                    return -1
                else:
                    ans += f[x][y]
        return ans

source = ""
target = ""
original = ["a","c"]
changed = ["b","a"]
cost = [788,444]
print(Solution().minimumCost(source, target, original, changed, cost))        